import{_ as t,o as a,c as i,ag as s}from"./chunks/framework.DXGyWiRo.js";const r="/assets/Pi-Under-Pressure-Screen-Main-v0_1_8_a.ohiMcCFQ.png",n="/assets/Pi-Under-Pressure-Screen-Results-v0_1_8_a.DRouuaI6.png",o="/assets/vcgencmd_x.D8pwlZpz.png",l="/assets/vcgencmd-get_throttled.DXQK0DUv.png",d="/assets/vcgencmd-measure.BeA3FC9x.png",h="/assets/DietPiOS-GeekBench6-3100vs2400.DG7yFIjJ.png",f=JSON.parse('{"title":"The Complete Raspberry Pi 5 Overclocking Guide","description":"Imported note from cmd0s/Pi-Under-Pressure (RPi5-OC-Guide.md)","frontmatter":{"title":"The Complete Raspberry Pi 5 Overclocking Guide","description":"Imported note from cmd0s/Pi-Under-Pressure (RPi5-OC-Guide.md)"},"headers":[],"relativePath":"microcontrollers-and-socs/raspberry-pi/overclocking-raspberry-pi-5/github-cmd0s-rpi5-overclocking-guide.md","filePath":"microcontrollers-and-socs/raspberry-pi/overclocking-raspberry-pi-5/github-cmd0s-rpi5-overclocking-guide.md"}'),p={name:"microcontrollers-and-socs/raspberry-pi/overclocking-raspberry-pi-5/github-cmd0s-rpi5-overclocking-guide.md"};function c(g,e,u,k,m,b){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="the-complete-raspberry-pi-5-overclocking-guide" tabindex="-1">The Complete Raspberry Pi 5 Overclocking Guide <a class="header-anchor" href="#the-complete-raspberry-pi-5-overclocking-guide" aria-label="Permalink to &quot;The Complete Raspberry Pi 5 Overclocking Guide&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://github.com/cmd0s/Pi-Under-Pressure/blob/main/RPi5-OC-Guide.md" target="_blank" rel="noreferrer">https://github.com/cmd0s/Pi-Under-Pressure/blob/main/RPi5-OC-Guide.md</a></li><li>Imported: 2025-06-23</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><h1 id="the-complete-raspberry-pi-5-overclocking-guide-1" tabindex="-1">The Complete Raspberry Pi 5 Overclocking Guide <a class="header-anchor" href="#the-complete-raspberry-pi-5-overclocking-guide-1" aria-label="Permalink to &quot;The Complete Raspberry Pi 5 Overclocking Guide&quot;">​</a></h1><p><em>Unlock the full potential of your Raspberry Pi 5 with safe, methodical overclocking</em></p><hr><h2 id="disclaimer" tabindex="-1">Disclaimer <a class="header-anchor" href="#disclaimer" aria-label="Permalink to &quot;Disclaimer&quot;">​</a></h2><p><strong>IMPORTANT: Read before proceeding</strong></p><p>Overclocking your Raspberry Pi 5 is done entirely <strong>at your own risk</strong>. This process may:</p><ul><li>Void your warranty</li><li>Cause permanent hardware damage</li><li>Lead to system instability, data corruption, or data loss</li><li>Reduce the lifespan of your device</li></ul><p>The author is not responsible for any damage resulting from following this guide. <strong>Raspberry Pi</strong> is a trademark of Raspberry Pi Ltd. The author is not affiliated with Raspberry Pi Ltd and uses this name purely for descriptive purposes.</p><p><strong>Active cooling is MANDATORY for overclocking.</strong> Do not attempt to overclock with passive cooling or no cooling solution.</p><hr><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ol><li><a href="#introduction">Introduction</a></li><li><a href="#prerequisites">Prerequisites</a></li><li><a href="#understanding-silicon-revisions-d0-vs-c1">Understanding Silicon Revisions (D0 vs C1)</a></li><li><a href="#default-values-and-parameters">Default Values and Parameters</a></li><li><a href="#editing-configtxt">Editing config.txt</a></li><li><a href="#firmware-update-procedures">Firmware Update Procedures</a></li><li><a href="#step-by-step-overclocking-procedure">Step-by-Step Overclocking Procedure</a></li><li><a href="#stability-testing-with-pi-under-pressure">Stability Testing with Pi-Under-Pressure</a></li><li><a href="#cpu-governor-settings">CPU Governor Settings</a></li><li><a href="#monitoring-and-diagnostics">Monitoring and Diagnostics</a></li><li><a href="#fan-speed-configuration">Fan Speed Configuration</a></li><li><a href="#pcie-gen-3-mode">PCIe Gen 3 Mode</a></li><li><a href="#understanding-throttling">Understanding Throttling</a></li><li><a href="#recovery-when-system-wont-boot">Recovery When System Won&#39;t Boot</a></li><li><a href="#performance-benchmarking">Performance Benchmarking</a></li><li><a href="#os-performance-differences">OS Performance Differences</a></li><li><a href="#achievable-results-and-silicon-lottery">Achievable Results and Silicon Lottery</a></li><li><a href="#best-practices-summary">Best Practices Summary</a></li><li><a href="#advanced-beyond-30-ghz">Advanced: Beyond 3.0 GHz</a></li><li><a href="#faq-and-troubleshooting">FAQ and Troubleshooting</a></li><li><a href="#reference-links">Reference Links</a></li></ol><hr><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>The Raspberry Pi 5, powered by the BCM2712 SoC with four Cortex-A76 cores, delivers impressive performance at its stock 2.4 GHz frequency. However, with proper cooling and configuration, many units can achieve stable operation at 2.8-3.0 GHz, unlocking significant additional performance for demanding workloads.</p><p>This guide provides a comprehensive, methodical approach to overclocking your Raspberry Pi 5 safely. We&#39;ll cover everything from basic configuration to advanced monitoring, with a focus on <strong>verifying stability</strong> using <a href="https://github.com/cmd0s/Pi-Under-Pressure" target="_blank" rel="noreferrer">Pi-Under-Pressure</a> — a specialized stress-testing tool designed specifically for overclocked Raspberry Pi systems.</p><p><strong>What you&#39;ll learn:</strong></p><ul><li>How to configure overclocking parameters</li><li>How to test stability at each frequency step</li><li>How to monitor your system during stress tests</li><li>How to recover if something goes wrong</li><li>Best practices for long-term stable operation</li></ul><hr><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before you begin overclocking, ensure you have:</p><h3 id="hardware-requirements" tabindex="-1">Hardware Requirements <a class="header-anchor" href="#hardware-requirements" aria-label="Permalink to &quot;Hardware Requirements&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>Requirement</th></tr></thead><tbody><tr><td><strong>Raspberry Pi 5</strong></td><td>2GB, 4GB, 8GB, or 16GB model (all work)</td></tr><tr><td><strong>Cooling</strong></td><td>Active cooling solution (Official Active Cooler minimum)</td></tr><tr><td><strong>Power Supply</strong></td><td>Official 27W USB-C power supply (5.1V / 5A)</td></tr><tr><td><strong>Storage</strong></td><td>microSD card or NVMe SSD</td></tr><tr><td><strong>Monitor</strong></td><td>HDMI display (recommended for seeing kernel panics)</td></tr></tbody></table><h3 id="software-requirements" tabindex="-1">Software Requirements <a class="header-anchor" href="#software-requirements" aria-label="Permalink to &quot;Software Requirements&quot;">​</a></h3><ul><li>64-bit Raspberry Pi OS or compatible distribution (DietPi, Ubuntu)</li><li>Updated system packages</li><li>Terminal access (SSH or direct)</li></ul><h3 id="before-you-start" tabindex="-1">Before You Start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before You Start&quot;">​</a></h3><ol><li><strong>Backup your data</strong> — Overclocking can cause system instability</li><li><strong>Update your system</strong> — Run <code>sudo apt update &amp;&amp; sudo apt full-upgrade -y</code></li><li><strong>Note your current settings</strong> — Document stock performance for comparison</li></ol><hr><h2 id="understanding-silicon-revisions-d0-vs-c1" tabindex="-1">Understanding Silicon Revisions (D0 vs C1) <a class="header-anchor" href="#understanding-silicon-revisions-d0-vs-c1" aria-label="Permalink to &quot;Understanding Silicon Revisions (D0 vs C1)&quot;">​</a></h2><p>Not all Raspberry Pi 5 units are identical. The BCM2712 SoC has been manufactured with different silicon steppings:</p><h3 id="stepping-versions" tabindex="-1">Stepping Versions <a class="header-anchor" href="#stepping-versions" aria-label="Permalink to &quot;Stepping Versions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Stepping</th><th>Chip ID</th><th>Models</th><th>Board Revision</th></tr></thead><tbody><tr><td><strong>C1</strong></td><td>BCM2712C1</td><td>Original 4GB, 8GB</td><td>rev 1.0</td></tr><tr><td><strong>D0</strong></td><td>BCM2712D0</td><td>2GB, 16GB, later 4GB/8GB</td><td>rev 1.1</td></tr></tbody></table><h3 id="d0-stepping-improvements" tabindex="-1">D0 Stepping Improvements <a class="header-anchor" href="#d0-stepping-improvements" aria-label="Permalink to &quot;D0 Stepping Improvements&quot;">​</a></h3><p>The D0 stepping features significant improvements:</p><ul><li><strong>33% smaller die</strong> (37.67mm² vs 55.84mm²)</li><li><strong>~30% lower idle power</strong> consumption (2.4W vs 3.3W)</li><li><strong>~4°C cooler</strong> under load</li><li>Removed unused &quot;dark silicon&quot; (Ethernet controller, UARTs 3-4, SDIO0)</li></ul><p><strong>Important:</strong> Despite these thermal advantages, D0 stepping does <strong>not</strong> provide higher maximum overclocking frequencies. The silicon lottery still determines your chip&#39;s maximum stable frequency.</p><p><strong>Practical implication:</strong> If you have a 16GB or 2GB model (or newer 4GB/8GB), you may see slightly lower temperatures during stress testing, but your maximum stable frequency will still depend on your specific chip.</p><p><em>Source: <a href="https://www.jeffgeerling.com/blog/2024/new-2gb-pi-5-has-33-smaller-die-30-idle-power-savings" target="_blank" rel="noreferrer">Jeff Geerling — New 2GB Pi 5 has 33% smaller die, 30% idle power savings</a></em></p><hr><h2 id="default-values-and-parameters" tabindex="-1">Default Values and Parameters <a class="header-anchor" href="#default-values-and-parameters" aria-label="Permalink to &quot;Default Values and Parameters&quot;">​</a></h2><p><strong>Note:</strong> These values may vary slightly depending on the operating system, firmware version, and board revision. Always verify your current settings before making changes.</p><h3 id="stock-configuration" tabindex="-1">Stock Configuration <a class="header-anchor" href="#stock-configuration" aria-label="Permalink to &quot;Stock Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Default Value</th><th>Description</th></tr></thead><tbody><tr><td><code>arm_freq</code></td><td>2400 MHz</td><td>CPU frequency</td></tr><tr><td><code>gpu_freq</code></td><td>910 MHz</td><td>VideoCore VII frequency</td></tr><tr><td><code>over_voltage</code></td><td>0</td><td>Voltage offset (legacy)</td></tr><tr><td><code>over_voltage_delta</code></td><td>0</td><td>Voltage offset in microvolts (recommended)</td></tr><tr><td><code>force_turbo</code></td><td>0</td><td>DVFS enabled (default)</td></tr></tbody></table><h3 id="overclocking-parameters" tabindex="-1">Overclocking Parameters <a class="header-anchor" href="#overclocking-parameters" aria-label="Permalink to &quot;Overclocking Parameters&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>Description</th></tr></thead><tbody><tr><td><code>arm_freq</code></td><td>2400-3000+ MHz</td><td>CPU clock frequency</td></tr><tr><td><code>gpu_freq</code></td><td>910-1100 MHz</td><td>GPU clock frequency</td></tr><tr><td><code>over_voltage_delta</code></td><td>0-50000+ µV</td><td>Voltage adjustment (preserves DVFS)</td></tr><tr><td><code>over_voltage</code></td><td>0-8</td><td>Legacy voltage offset (disables DVFS)</td></tr><tr><td><code>force_turbo</code></td><td>0 or 1</td><td>Force maximum frequency always</td></tr></tbody></table><blockquote><p><strong>Tip: Start with CPU only</strong></p><p>When beginning your overclocking journey, focus on <code>arm_freq</code> first and leave <code>gpu_freq</code> at default (910 MHz). This makes troubleshooting easier — if you change both simultaneously and experience instability, you won&#39;t know which one is causing the problem. Only increase <code>gpu_freq</code> after you&#39;ve found a stable CPU frequency, and only if you have a specific use case (desktop graphics, V3D, video encoding).</p></blockquote><h3 id="why-use-over-voltage-delta-instead-of-over-voltage" tabindex="-1">Why Use over_voltage_delta Instead of over_voltage? <a class="header-anchor" href="#why-use-over-voltage-delta-instead-of-over-voltage" aria-label="Permalink to &quot;Why Use over_voltage_delta Instead of over_voltage?&quot;">​</a></h3><p>The <code>over_voltage_delta</code> parameter is <strong>strongly recommended</strong> over the legacy <code>over_voltage</code> because:</p><ol><li><strong>Preserves DVFS</strong> — Dynamic Voltage and Frequency Scaling continues to work</li><li><strong>Better power efficiency</strong> — System can still downclock when idle</li><li><strong>Finer control</strong> — Adjustments in microvolts instead of fixed steps</li><li><strong>Lower idle temperatures</strong> — Voltage scales with frequency</li></ol><h3 id="over-voltage-delta-value-guide" tabindex="-1">over_voltage_delta Value Guide <a class="header-anchor" href="#over-voltage-delta-value-guide" aria-label="Permalink to &quot;over_voltage_delta Value Guide&quot;">​</a></h3><p>The value is specified in <strong>microvolts (µV)</strong>. The maximum effective voltage is <strong>capped at 1.0V</strong> by hardware, regardless of settings.</p><table tabindex="0"><thead><tr><th>Value (µV)</th><th>Voltage Added</th><th>Risk Level</th><th>Typical Use Case</th></tr></thead><tbody><tr><td>0</td><td>+0.000V</td><td>Safe</td><td>Stock operation</td></tr><tr><td>10000</td><td>+0.010V</td><td>Safe</td><td>Mild OC (2.5-2.6 GHz)</td></tr><tr><td>25000</td><td>+0.025V</td><td>Safe</td><td>Conservative OC (2.7-2.8 GHz)</td></tr><tr><td>50000</td><td>+0.050V</td><td>Moderate</td><td>Common stable OC (2.8-3.0 GHz)</td></tr><tr><td>75000</td><td>+0.075V</td><td>Higher</td><td>Pushing limits (3.0 GHz)</td></tr><tr><td>100000+</td><td>+0.100V+</td><td>High</td><td>Extreme OC (not recommended)</td></tr></tbody></table><p><strong>Recommendations:</strong></p><ul><li><strong>Start low</strong> — Begin with <code>over_voltage_delta=0</code> and only increase if stability tests fail</li><li><strong>Safe zone</strong> — Values up to 50000 µV are generally considered safe for daily use</li><li><strong>Caution zone</strong> — Values 50000-75000 µV require excellent cooling</li><li><strong>Danger zone</strong> — Values above 75000 µV significantly increase heat and may reduce chip lifespan</li><li><strong>Hardware limit</strong> — The BCM2712 has a hard cap at 1.0V; higher delta values won&#39;t exceed this</li></ul><p><strong>Undervolting:</strong> The value is a signed integer, so negative values (e.g., <code>-5000</code>) can be used for undervolting to reduce power consumption and heat.</p><p><em>Sources: <a href="https://forums.raspberrypi.com/viewtopic.php?t=362296" target="_blank" rel="noreferrer">Raspberry Pi Forums</a>, <a href="https://www.jeffgeerling.com/blog/2023/overclocking-and-underclocking-raspberry-pi-5" target="_blank" rel="noreferrer">Jeff Geerling</a></em></p><h3 id="what-does-force-turbo-1-do" tabindex="-1">What Does force_turbo=1 Do? <a class="header-anchor" href="#what-does-force-turbo-1-do" aria-label="Permalink to &quot;What Does force_turbo=1 Do?&quot;">​</a></h3><p>By default (<code>force_turbo=0</code>), the CPU frequency governor dynamically adjusts clock speeds:</p><ul><li><strong>Under load</strong> — Clocks increase to maximum frequency</li><li><strong>At idle</strong> — Clocks drop to minimum frequency to save power</li></ul><p>Setting <code>force_turbo=1</code>:</p><ul><li><strong>Forces maximum frequency at all times</strong>, even when idle</li><li><strong>Increases power consumption</strong> and heat during idle</li><li><strong>Disables frequency scaling</strong> part of DVFS (voltage scaling may still work)</li></ul><p><strong>When to use:</strong></p><ul><li>Benchmarking (ensures consistent maximum performance)</li><li>Latency-sensitive applications</li><li>When you want to eliminate frequency ramping delays</li></ul><p><strong>When NOT to use:</strong></p><ul><li>Daily operation (unnecessary power consumption)</li><li>24/7 running systems (extra heat, wear)</li></ul><p><strong>Important:</strong> Raspberry Pi officially discourages using <code>force_turbo=1</code> for normal overclocking. It&#39;s primarily a benchmarking tool. For daily use, rely on the CPU governor to manage frequencies dynamically.</p><hr><h2 id="editing-config-txt" tabindex="-1">Editing config.txt <a class="header-anchor" href="#editing-config-txt" aria-label="Permalink to &quot;Editing config.txt&quot;">​</a></h2><h3 id="file-location" tabindex="-1">File Location <a class="header-anchor" href="#file-location" aria-label="Permalink to &quot;File Location&quot;">​</a></h3><p>On Raspberry Pi OS (Trixie, Bookworm, and newer), the configuration file is located at:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/boot/firmware/config.txt</span></span></code></pre></div><p><strong>Note:</strong> Older guides may reference <code>/boot/config.txt</code>. On modern Raspberry Pi OS, a symlink exists for backwards compatibility, but always use <code>/boot/firmware/config.txt</code> to avoid issues.</p><h3 id="how-to-edit" tabindex="-1">How to Edit <a class="header-anchor" href="#how-to-edit" aria-label="Permalink to &quot;How to Edit&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /boot/firmware/config.txt</span></span></code></pre></div><p><strong>Saving and applying changes:</strong></p><ol><li>Press <code>Ctrl+X</code> to exit nano</li><li>When prompted &quot;Save modified buffer?&quot;, press <code>Y</code> to confirm</li><li>Press <code>Enter</code> to confirm the filename</li><li><strong>Reboot is required</strong> for changes to take effect:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reboot</span></span></code></pre></div></li></ol><p>Changes to <code>config.txt</code> are only applied during boot. The system reads this file before the Linux kernel starts, so there is no way to apply changes without rebooting.</p><h3 id="example-overclock-configuration" tabindex="-1">Example Overclock Configuration <a class="header-anchor" href="#example-overclock-configuration" aria-label="Permalink to &quot;Example Overclock Configuration&quot;">​</a></h3><p>Add these lines under the <code>[pi5]</code> section (create it if it doesn&#39;t exist):</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[pi5]</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Overclocking settings</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">arm_freq</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=2800</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">gpu_freq</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=1000</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">over_voltage_delta</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=50000</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Optional: Force turbo</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># force_turbo=1</span></span></code></pre></div><h3 id="safe-starting-point" tabindex="-1">Safe Starting Point <a class="header-anchor" href="#safe-starting-point" aria-label="Permalink to &quot;Safe Starting Point&quot;">​</a></h3><p>For initial testing, start with a conservative overclock:</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[pi5]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">arm_freq</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=2600</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">over_voltage_delta</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=10000</span></span></code></pre></div><p><em>For complete documentation, see: <a href="https://www.raspberrypi.com/documentation/computers/config_txt.html" target="_blank" rel="noreferrer">Raspberry Pi config.txt Documentation</a></em></p><hr><h2 id="firmware-update-procedures" tabindex="-1">Firmware Update Procedures <a class="header-anchor" href="#firmware-update-procedures" aria-label="Permalink to &quot;Firmware Update Procedures&quot;">​</a></h2><p>Keeping your firmware updated is important for stability and compatibility with overclocking.</p><h3 id="standard-method-apt" tabindex="-1">Standard Method (apt) <a class="header-anchor" href="#standard-method-apt" aria-label="Permalink to &quot;Standard Method (apt)&quot;">​</a></h3><p>This installs stable, tested firmware versions:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> full-upgrade</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rpi-eeprom-update</span></span></code></pre></div><p>To apply a pending update:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rpi-eeprom-update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reboot</span></span></code></pre></div><h3 id="advanced-method-rpi-eeprom-from-github-—-recommended-for-oc" tabindex="-1">Advanced Method (rpi-eeprom from GitHub) — Recommended for OC <a class="header-anchor" href="#advanced-method-rpi-eeprom-from-github-—-recommended-for-oc" aria-label="Permalink to &quot;Advanced Method (rpi-eeprom from GitHub) — Recommended for OC&quot;">​</a></h3><p>For the latest bleeding-edge EEPROM firmware, use the official rpi-eeprom repository:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/raspberrypi/rpi-eeprom.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rpi-eeprom</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./test/install</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # Install latest firmware</span></span></code></pre></div><p>For beta/bleeding-edge firmware:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./test/install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Install beta firmware</span></span></code></pre></div><p><strong>What this does:</strong></p><ul><li>Copies firmware to <code>/lib/firmware/raspberrypi/bootloader</code></li><li>Installs <code>rpi-eeprom-config</code>, <code>rpi-eeprom-digest</code>, <code>rpi-eeprom-update</code> to <code>/usr/bin</code></li><li>Updates configuration at <code>/etc/default/rpi-eeprom-update</code></li></ul><p><strong>After installation, apply the update:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rpi-eeprom-update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reboot</span></span></code></pre></div><p><strong>Verify the update:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rpi-eeprom-update</span></span></code></pre></div><p><em>Source: <a href="https://github.com/raspberrypi/rpi-eeprom" target="_blank" rel="noreferrer">GitHub — raspberrypi/rpi-eeprom</a></em></p><hr><h2 id="step-by-step-overclocking-procedure" tabindex="-1">Step-by-Step Overclocking Procedure <a class="header-anchor" href="#step-by-step-overclocking-procedure" aria-label="Permalink to &quot;Step-by-Step Overclocking Procedure&quot;">​</a></h2><p>Follow this methodical approach to find your maximum stable frequency:</p><h3 id="the-process" tabindex="-1">The Process <a class="header-anchor" href="#the-process" aria-label="Permalink to &quot;The Process&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  1. Start at stock (2400 MHz)                               │</span></span>
<span class="line"><span>│                    ↓                                        │</span></span>
<span class="line"><span>│  2. Increase arm_freq by 50 MHz                             │</span></span>
<span class="line"><span>│                    ↓                                        │</span></span>
<span class="line"><span>│  3. Reboot                                                  │</span></span>
<span class="line"><span>│                    ↓                                        │</span></span>
<span class="line"><span>│  4. Run Pi-Under-Pressure for 3 minutes                     │</span></span>
<span class="line"><span>│                    ↓                                        │</span></span>
<span class="line"><span>│  ┌──────────────────────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │ PASSED (green)?                                       │  │</span></span>
<span class="line"><span>│  │   YES → Go to step 2, increase by another 50 MHz     │  │</span></span>
<span class="line"><span>│  │   NO  → Add over_voltage_delta (+10000 µV)           │  │</span></span>
<span class="line"><span>│  │         Retest. If still fails, reduce arm_freq      │  │</span></span>
<span class="line"><span>│  └──────────────────────────────────────────────────────┘  │</span></span>
<span class="line"><span>│                    ↓                                        │</span></span>
<span class="line"><span>│  5. When stable at target frequency, run extended test (1h+)│</span></span>
<span class="line"><span>│                    ↓                                        │</span></span>
<span class="line"><span>│  6. If extended test passes → OC successful!                │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="example-progression" tabindex="-1">Example Progression <a class="header-anchor" href="#example-progression" aria-label="Permalink to &quot;Example Progression&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Step</th><th>arm_freq</th><th>over_voltage_delta</th><th>Result</th></tr></thead><tbody><tr><td>1</td><td>2400 MHz</td><td>0</td><td>Baseline (stock)</td></tr><tr><td>2</td><td>2450 MHz</td><td>0</td><td>PASSED</td></tr><tr><td>3</td><td>2500 MHz</td><td>0</td><td>PASSED</td></tr><tr><td>4</td><td>2550 MHz</td><td>0</td><td>PASSED</td></tr><tr><td>5</td><td>2600 MHz</td><td>0</td><td>PASSED</td></tr><tr><td>6</td><td>2650 MHz</td><td>0</td><td>PASSED</td></tr><tr><td>7</td><td>2700 MHz</td><td>0</td><td>FAILED (errors)</td></tr><tr><td>8</td><td>2700 MHz</td><td>10000</td><td>PASSED</td></tr><tr><td>9</td><td>2750 MHz</td><td>10000</td><td>PASSED</td></tr><tr><td>10</td><td>2800 MHz</td><td>10000</td><td>FAILED</td></tr><tr><td>11</td><td>2800 MHz</td><td>20000</td><td>PASSED</td></tr><tr><td>12</td><td>2800 MHz</td><td>20000</td><td><strong>1h test → PASSED</strong> ✓</td></tr></tbody></table><p><strong>Final stable configuration:</strong> <code>arm_freq=2800</code>, <code>over_voltage_delta=20000</code></p><blockquote><p><strong>Tip: Speed up the process</strong></p><p>You don&#39;t have to start from stock 2400 MHz. The vast majority of Raspberry Pi 5 units will boot and run stable at <strong>2600-2700 MHz</strong> without any voltage adjustment. To save time:</p><ol><li>Start directly at <code>arm_freq=2600</code> (or even <code>2700</code>)</li><li>If it boots and passes a quick 3-minute test, continue increasing</li><li>If it fails to boot or crashes, step back to 2500 MHz and work your way up</li></ol><p>This approach can save you 10-15 iterations in the tuning process.</p></blockquote><hr><h2 id="stability-testing-with-pi-under-pressure" tabindex="-1">Stability Testing with Pi-Under-Pressure <a class="header-anchor" href="#stability-testing-with-pi-under-pressure" aria-label="Permalink to &quot;Stability Testing with Pi-Under-Pressure&quot;">​</a></h2><p><strong>Pi-Under-Pressure</strong> is a specialized stability testing tool designed specifically for overclocked Raspberry Pi 5 systems. It simultaneously stresses CPU, RAM, and optionally NVMe storage while monitoring for errors, throttling, and thermal issues.</p><h3 id="why-pi-under-pressure" tabindex="-1">Why <a href="https://github.com/cmd0s/Pi-Under-Pressure" target="_blank" rel="noreferrer">Pi-Under-Pressure</a>? <a class="header-anchor" href="#why-pi-under-pressure" aria-label="Permalink to &quot;Why [Pi-Under-Pressure](https://github.com/cmd0s/Pi-Under-Pressure)?&quot;">​</a></h3><ul><li><strong>Multi-component stress testing</strong> — Tests CPU, RAM, and NVMe simultaneously</li><li><strong>Real-time monitoring</strong> — Temperature, throttling, frequency, and errors</li><li><strong>I/O error detection</strong> — Monitors kernel logs for I/O errors and hardware issues (with <code>-e</code> flag)</li><li><strong>Designed for Pi 5</strong> — Optimized for ARM Cortex-A76 architecture</li><li><strong>Clear pass/fail results</strong> — Green = stable, Red = unstable</li></ul><h3 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/cmd0s/Pi-Under-Pressure/main/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><h3 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h3><p><strong>Quick stability check (3 minutes):</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pi-under-pressure</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 3m</span></span></code></pre></div><p><strong>Extended stability test (1 hour):</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pi-under-pressure</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1h</span></span></code></pre></div><p><strong>Full test with NVMe stress:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pi-under-pressure</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span></span></code></pre></div><p><strong>With video encoder stress (requires ffmpeg):</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pi-under-pressure</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -V</span></span></code></pre></div><h3 id="what-it-tests" tabindex="-1">What It Tests <a class="header-anchor" href="#what-it-tests" aria-label="Permalink to &quot;What It Tests&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>Workloads</th></tr></thead><tbody><tr><td><strong>CPU</strong></td><td>DFT, Matrix Multiplication, Prime Sieve, AES-256 Encryption</td></tr><tr><td><strong>RAM</strong></td><td>Sequential patterns, Random access, Fill &amp; verify, STREAM-like bandwidth</td></tr><tr><td><strong>NVMe</strong></td><td>4K random I/O, Sequential read/write, Mixed workload</td></tr><tr><td><strong>Video</strong></td><td>H.264/H.265 hardware encoding (optional)</td></tr></tbody></table><h3 id="understanding-results" tabindex="-1">Understanding Results <a class="header-anchor" href="#understanding-results" aria-label="Permalink to &quot;Understanding Results&quot;">​</a></h3><p><strong>A test is successful ONLY if:</strong></p><ol><li>✅ The test runs to <strong>completion</strong> (no crashes, freezes, or kernel panics)</li><li>✅ The final report displays in <strong>GREEN</strong> showing <strong>PASSED</strong></li><li>✅ <strong>Zero errors</strong> in all categories (CPU, RAM, NVMe, throttling)</li></ol><p><strong>If ANY of these conditions are not met, your overclock is NOT stable.</strong></p><p><img src="`+r+'" alt="Pi-Under-Pressure-Screen-Main-v0_1_8_a"></p><p><img src="'+n+`" alt="Pi-Under-Pressure-Screen-Results-v0_1_8_a"></p><h3 id="testing-strategy" tabindex="-1">Testing Strategy <a class="header-anchor" href="#testing-strategy" aria-label="Permalink to &quot;Testing Strategy&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Phase</th><th>Duration</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Quick check</strong></td><td>3 minutes</td><td>Fast validation after each frequency change</td></tr><tr><td><strong>Confirmation</strong></td><td>15-30 minutes</td><td>Verify stability before moving to next step</td></tr><tr><td><strong>Final validation</strong></td><td>1+ hours</td><td>Confirm long-term stability</td></tr><tr><td><strong>Burn-in</strong></td><td>8+ hours</td><td>Maximum confidence (optional)</td></tr></tbody></table><p><strong>Time-saving tip:</strong> Start with 3-minute tests. Only run extended tests once you&#39;ve found a frequency that passes the quick check. This saves significant time during the iterative tuning process.</p><p><em>Source: <a href="https://github.com/cmd0s/Pi-Under-Pressure" target="_blank" rel="noreferrer">Pi-Under-Pressure on GitHub</a></em></p><hr><h2 id="cpu-governor-settings" tabindex="-1">CPU Governor Settings <a class="header-anchor" href="#cpu-governor-settings" aria-label="Permalink to &quot;CPU Governor Settings&quot;">​</a></h2><p>The CPU governor controls how the processor scales its frequency based on load.</p><h3 id="available-governors" tabindex="-1">Available Governors <a class="header-anchor" href="#available-governors" aria-label="Permalink to &quot;Available Governors&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Governor</th><th>Description</th></tr></thead><tbody><tr><td><code>ondemand</code></td><td>Default on Pi OS. Scales frequency based on CPU load</td></tr><tr><td><code>schedutil</code></td><td>More responsive, uses scheduler data</td></tr><tr><td><code>performance</code></td><td>Maximum frequency always. Best for benchmarks</td></tr><tr><td><code>powersave</code></td><td>Minimum frequency always. Maximum efficiency</td></tr></tbody></table><h3 id="check-current-governor" tabindex="-1">Check Current Governor <a class="header-anchor" href="#check-current-governor" aria-label="Permalink to &quot;Check Current Governor&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/devices/system/cpu/cpufreq/policy0/scaling_governor</span></span></code></pre></div><h3 id="temporary-change-resets-on-reboot" tabindex="-1">Temporary Change (resets on reboot) <a class="header-anchor" href="#temporary-change-resets-on-reboot" aria-label="Permalink to &quot;Temporary Change (resets on reboot)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> performance</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tee</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/devices/system/cpu/cpufreq/policy0/scaling_governor</span></span></code></pre></div><p>Verify the change:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/devices/system/cpu/cpufreq/policy0/scaling_governor</span></span></code></pre></div><h3 id="permanent-change-using-cpufrequtils" tabindex="-1">Permanent Change (using cpufrequtils) <a class="header-anchor" href="#permanent-change-using-cpufrequtils" aria-label="Permalink to &quot;Permanent Change (using cpufrequtils)&quot;">​</a></h3><p>Install cpufrequtils:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cpufrequtils</span></span></code></pre></div><p>Edit the configuration file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/default/cpufrequtils</span></span></code></pre></div><p>Add the following line:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GOVERNOR=&quot;performance&quot;</span></span></code></pre></div><p>Save the file, then enable and start the service:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cpufrequtils</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cpufrequtils</span></span></code></pre></div><p>After reboot, verify the setting persists:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/devices/system/cpu/cpufreq/policy0/scaling_governor</span></span></code></pre></div><h3 id="recommendation-for-overclocking" tabindex="-1">Recommendation for Overclocking <a class="header-anchor" href="#recommendation-for-overclocking" aria-label="Permalink to &quot;Recommendation for Overclocking&quot;">​</a></h3><p>Use <code>schedutil</code> for daily use — it&#39;s more responsive than <code>ondemand</code> and still allows power saving when idle. Use <code>performance</code> only during benchmarking or stress testing.</p><hr><h2 id="monitoring-and-diagnostics" tabindex="-1">Monitoring and Diagnostics <a class="header-anchor" href="#monitoring-and-diagnostics" aria-label="Permalink to &quot;Monitoring and Diagnostics&quot;">​</a></h2><h3 id="essential-commands" tabindex="-1">Essential Commands <a class="header-anchor" href="#essential-commands" aria-label="Permalink to &quot;Essential Commands&quot;">​</a></h3><p><strong>Check CPU temperature:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vcgencmd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> measure_temp</span></span></code></pre></div><p><strong>Check current CPU frequency:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vcgencmd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> measure_clock</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arm</span></span></code></pre></div><p><strong>Check GPU frequency:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vcgencmd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> measure_clock</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> core</span></span></code></pre></div><p><strong>Check voltage:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vcgencmd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pmic_read_adc</span></span></code></pre></div><p>Look for <code>EXT5V_V</code> — this shows the actual voltage your Pi is receiving.</p><h3 id="throttling-status" tabindex="-1">Throttling Status <a class="header-anchor" href="#throttling-status" aria-label="Permalink to &quot;Throttling Status&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vcgencmd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get_throttled</span></span></code></pre></div><p>This returns a hexadecimal value representing the current and historical throttling status.</p><p><img src="`+o+'" alt="vcgencmd commands"></p><h3 id="throttle-flag-meanings" tabindex="-1">Throttle Flag Meanings <a class="header-anchor" href="#throttle-flag-meanings" aria-label="Permalink to &quot;Throttle Flag Meanings&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Bit</th><th>Hex Mask</th><th>Current State</th><th>Meaning</th></tr></thead><tbody><tr><td>0</td><td>0x1</td><td>Under-voltage detected</td><td>Power supply issue</td></tr><tr><td>1</td><td>0x2</td><td>Arm frequency capped</td><td>Frequency limited</td></tr><tr><td>2</td><td>0x4</td><td>Currently throttled</td><td>Active thermal throttling</td></tr><tr><td>3</td><td>0x8</td><td>Soft temperature limit</td><td>Approaching thermal limit</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Bit</th><th>Hex Mask</th><th>Historical (Since Boot)</th><th>Meaning</th></tr></thead><tbody><tr><td>16</td><td>0x10000</td><td>Under-voltage has occurred</td><td>Power issue since boot</td></tr><tr><td>17</td><td>0x20000</td><td>Arm frequency capping occurred</td><td>Was limited since boot</td></tr><tr><td>18</td><td>0x40000</td><td>Throttling has occurred</td><td>Was throttled since boot</td></tr><tr><td>19</td><td>0x80000</td><td>Soft temperature limit occurred</td><td>Hit limit since boot</td></tr></tbody></table><p><strong>Important:</strong> Historical bits (16-19) are &quot;sticky&quot; — they remain set until you reboot. If you see <code>0x50000</code> but no current issues (bits 0-3 are clear), it means the problem occurred earlier but has since resolved. A reboot will clear the historical bits.</p><h3 id="common-values" tabindex="-1">Common Values <a class="header-anchor" href="#common-values" aria-label="Permalink to &quot;Common Values&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Value</th><th>Meaning</th></tr></thead><tbody><tr><td><code>0x0</code></td><td><strong>Perfect</strong> — No issues ever</td></tr><tr><td><code>0x50000</code></td><td>Under-voltage and throttling occurred at some point</td></tr><tr><td><code>0x50005</code></td><td>Currently under-voltage AND throttled</td></tr></tbody></table><p><strong>For a successful overclock, you want <code>0x0</code> after a stress test.</strong></p><p><img src="'+l+'" alt="vcgencmd-get_throttled"></p><h3 id="continuous-monitoring" tabindex="-1">Continuous Monitoring <a class="header-anchor" href="#continuous-monitoring" aria-label="Permalink to &quot;Continuous Monitoring&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> watch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;vcgencmd measure_temp &amp;&amp; vcgencmd measure_clock arm &amp;&amp; vcgencmd get_throttled&#39;</span></span></code></pre></div><p><img src="'+d+`" alt="vcgencmd-measure"></p><hr><h2 id="fan-speed-configuration" tabindex="-1">Fan Speed Configuration <a class="header-anchor" href="#fan-speed-configuration" aria-label="Permalink to &quot;Fan Speed Configuration&quot;">​</a></h2><h3 id="typical-fan-behavior" tabindex="-1">Typical Fan Behavior <a class="header-anchor" href="#typical-fan-behavior" aria-label="Permalink to &quot;Typical Fan Behavior&quot;">​</a></h3><p>The official Active Cooler uses PWM control. These are <strong>typical values</strong> — actual defaults may vary depending on firmware version and cooling solution:</p><table tabindex="0"><thead><tr><th>Temperature</th><th>Fan Speed</th></tr></thead><tbody><tr><td>Below 50°C</td><td>Off</td></tr><tr><td>50°C</td><td>30% (speed 75)</td></tr><tr><td>60°C</td><td>50% (speed 125)</td></tr><tr><td>67.5°C</td><td>70% (speed 175)</td></tr><tr><td>75°C</td><td>100% (speed 250)</td></tr></tbody></table><p><strong>Recommendation:</strong> For overclocking, always configure your own fan curve to ensure adequate cooling rather than relying on defaults.</p><h3 id="custom-fan-configuration" tabindex="-1">Custom Fan Configuration <a class="header-anchor" href="#custom-fan-configuration" aria-label="Permalink to &quot;Custom Fan Configuration&quot;">​</a></h3><p>Add these parameters to <code>/boot/firmware/config.txt</code>:</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># More aggressive cooling for overclocking</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dtparam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fan_temp0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=45000</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dtparam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fan_temp0_hyst</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=5000</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dtparam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fan_temp0_speed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=100</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dtparam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fan_temp1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=55000</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dtparam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fan_temp1_hyst</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=5000</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dtparam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fan_temp1_speed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=150</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dtparam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fan_temp2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=65000</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dtparam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fan_temp2_hyst</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=5000</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dtparam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fan_temp2_speed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=200</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dtparam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fan_temp3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=70000</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dtparam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fan_temp3_hyst</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=5000</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dtparam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fan_temp3_speed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=255</span></span></code></pre></div><p><strong>Parameters explained:</strong></p><ul><li><code>fan_tempX</code> — Temperature threshold in millidegrees (45000 = 45°C)</li><li><code>fan_tempX_hyst</code> — Hysteresis to prevent rapid on/off cycling</li><li><code>fan_tempX_speed</code> — PWM value 0-255 (255 = maximum)</li></ul><hr><h2 id="pcie-gen-3-mode" tabindex="-1">PCIe Gen 3 Mode <a class="header-anchor" href="#pcie-gen-3-mode" aria-label="Permalink to &quot;PCIe Gen 3 Mode&quot;">​</a></h2><p>The Raspberry Pi 5 features a single PCIe lane that officially operates at <strong>PCIe Generation 2</strong> speeds. However, forcing PCIe Gen 3 mode is a simple configuration change that <strong>doubles the bandwidth</strong> — a form of overclocking that&#39;s particularly beneficial for NVMe storage users.</p><h3 id="default-vs-overclocked-pcie" tabindex="-1">Default vs Overclocked PCIe <a class="header-anchor" href="#default-vs-overclocked-pcie" aria-label="Permalink to &quot;Default vs Overclocked PCIe&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>Speed</th><th>Bandwidth</th><th>Status</th></tr></thead><tbody><tr><td><strong>Gen 2</strong> (default)</td><td>5 GT/s</td><td>~500 MB/s</td><td>Officially supported</td></tr><tr><td><strong>Gen 3</strong> (forced)</td><td>8 GT/s</td><td>~1000 MB/s</td><td>Unofficially supported</td></tr></tbody></table><h3 id="why-force-gen-3" tabindex="-1">Why Force Gen 3? <a class="header-anchor" href="#why-force-gen-3" aria-label="Permalink to &quot;Why Force Gen 3?&quot;">​</a></h3><p>While PCIe Gen 3 is not officially supported by Raspberry Pi, in practice:</p><ul><li><strong>It works very well</strong> — Almost all NVMe adapters and drives handle Gen 3 speeds correctly</li><li><strong>Double the throughput</strong> — Significant improvement for NVMe SSD performance</li><li><strong>No stability issues</strong> — From extensive testing, Gen 3 mode is reliable for daily use</li><li><strong>Easy to enable</strong> — Simple config.txt change, easy to revert if needed</li></ul><h3 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h3><p>Add the following lines to <code>/boot/firmware/config.txt</code> under the <code>[pi5]</code> or <code>[all]</code> section:</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[pi5]</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Enable PCIe</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dtparam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=pciex1</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Enable PCIe Gen 3 (default is Gen 2)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dtparam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">pciex1_gen</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=3</span></span></code></pre></div><p><strong>After adding these lines, reboot for changes to take effect.</strong></p><h3 id="verification" tabindex="-1">Verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Verification&quot;">​</a></h3><p>After rebooting, verify the PCIe link speed:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lspci</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vv</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;lnksta:&quot;</span></span></code></pre></div><p>Look for <code>Speed 8GT/s</code> to confirm Gen 3 mode is active.</p><h3 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h3><ul><li><strong>NVMe SSD users</strong> — If you&#39;re booting from or using NVMe storage, Gen 3 provides a noticeable performance improvement</li><li><strong>High-bandwidth peripherals</strong> — Any PCIe device that can benefit from increased bandwidth</li></ul><h3 id="compatibility-notes" tabindex="-1">Compatibility Notes <a class="header-anchor" href="#compatibility-notes" aria-label="Permalink to &quot;Compatibility Notes&quot;">​</a></h3><ul><li><strong>Most adapters work</strong> — The vast majority of NVMe HATs and adapters support Gen 3 speeds without issues</li><li><strong>Some older devices may not work</strong> — If you experience instability, remove the <code>pciex1_gen=3</code> line to revert to Gen 2</li><li><strong>Official Pi HAT+</strong> — The official Raspberry Pi M.2 HAT+ works reliably with Gen 3 enabled</li></ul><hr><h2 id="understanding-throttling" tabindex="-1">Understanding Throttling <a class="header-anchor" href="#understanding-throttling" aria-label="Permalink to &quot;Understanding Throttling&quot;">​</a></h2><p>Throttling is your Pi&#39;s protection mechanism against overheating or power issues.</p><h3 id="types-of-throttling" tabindex="-1">Types of Throttling <a class="header-anchor" href="#types-of-throttling" aria-label="Permalink to &quot;Types of Throttling&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Trigger</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>Thermal throttling</strong></td><td>CPU &gt; 80°C</td><td>Reduces frequency to lower temperature</td></tr><tr><td><strong>Hard thermal limit</strong></td><td>CPU &gt; 85°C</td><td>Aggressive frequency reduction, overclock/overvoltage may be disabled</td></tr><tr><td><strong>Under-voltage</strong></td><td>Voltage &lt; 4.63V</td><td>Caps frequency to reduce power draw</td></tr></tbody></table><p><strong>Note about <code>temp_limit</code>:</strong> The <code>config.txt</code> parameter <code>temp_limit</code> (default 85) sets the hard thermal limit. This is the point where aggressive throttling kicks in. The soft throttling starts earlier around 80°C.</p><h3 id="why-throttling-failed-overclock" tabindex="-1">Why Throttling = Failed Overclock <a class="header-anchor" href="#why-throttling-failed-overclock" aria-label="Permalink to &quot;Why Throttling = Failed Overclock&quot;">​</a></h3><p>If your system throttles during a stability test, your overclock is <strong>not stable</strong>. The system is protecting itself by reducing performance, which means:</p><ol><li>You won&#39;t get the performance you&#39;re targeting</li><li>The system is operating at its limits</li><li>Long-term reliability may be compromised</li></ol><p><strong>Solution:</strong> Either reduce <code>arm_freq</code> or increase <code>over_voltage_delta</code> until throttling no longer occurs.</p><h2 id="recovery-when-system-won-t-boot" tabindex="-1">Recovery When System Won&#39;t Boot <a class="header-anchor" href="#recovery-when-system-won-t-boot" aria-label="Permalink to &quot;Recovery When System Won&#39;t Boot&quot;">​</a></h2><p>If your Pi won&#39;t boot after applying overclock settings, don&#39;t panic.</p><h3 id="method-1-edit-config-txt-on-another-computer-recommended" tabindex="-1">Method 1: Edit config.txt on Another Computer (Recommended) <a class="header-anchor" href="#method-1-edit-config-txt-on-another-computer-recommended" aria-label="Permalink to &quot;Method 1: Edit config.txt on Another Computer (Recommended)&quot;">​</a></h3><ol><li>Power off the Pi</li><li>Remove the microSD card</li><li>Insert it into another computer (Windows, Mac, or Linux)</li><li>Open the <code>bootfs</code> partition</li><li>Edit <code>config.txt</code> (in <code>/boot/firmware/</code> or root of boot partition)</li><li>Comment out or remove your overclock settings:</li></ol><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[pi5]</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># arm_freq=3000        # Commented out</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># over_voltage_delta=50000</span></span></code></pre></div><ol start="7"><li>Save, eject, reinsert into Pi, and boot</li></ol><h3 id="method-2-hold-shift-during-boot-less-reliable" tabindex="-1">Method 2: Hold Shift During Boot (Less Reliable) <a class="header-anchor" href="#method-2-hold-shift-during-boot-less-reliable" aria-label="Permalink to &quot;Method 2: Hold Shift During Boot (Less Reliable)&quot;">​</a></h3><p>Holding the Shift key during boot can temporarily disable overclock settings on some configurations.</p><p><strong>Note:</strong> This method is less reliable on Pi 5 — it depends on boot flow, firmware version, keyboard type, and HDMI connection. If it doesn&#39;t work for you, use Method 1 (editing config.txt from another computer).</p><h3 id="kernel-panic-visibility" tabindex="-1">Kernel Panic Visibility <a class="header-anchor" href="#kernel-panic-visibility" aria-label="Permalink to &quot;Kernel Panic Visibility&quot;">​</a></h3><p>If you have an HDMI monitor connected, kernel panics will be visible on screen. This can help diagnose whether the issue is an overclock-related crash or something else.</p><h2 id="performance-benchmarking" tabindex="-1">Performance Benchmarking <a class="header-anchor" href="#performance-benchmarking" aria-label="Permalink to &quot;Performance Benchmarking&quot;">​</a></h2><h3 id="geekbench-6-primary-benchmark" tabindex="-1">GeekBench 6 (Primary Benchmark) <a class="header-anchor" href="#geekbench-6-primary-benchmark" aria-label="Permalink to &quot;GeekBench 6 (Primary Benchmark)&quot;">​</a></h3><p>GeekBench 6 is the standard benchmark for comparing Raspberry Pi 5 performance.</p><p><strong>Installation:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://cdn.geekbench.com/Geekbench-6.4.0-LinuxARMPreview.tar.gz</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -xzf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Geekbench-6.4.0-LinuxARMPreview.tar.gz</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Geekbench-6.4.0-LinuxARMPreview</span></span></code></pre></div><p><strong>Run the benchmark:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./geekbench6</span></span></code></pre></div><h3 id="geekbench-6-scores" tabindex="-1">GeekBench 6 Scores <a class="header-anchor" href="#geekbench-6-scores" aria-label="Permalink to &quot;GeekBench 6 Scores&quot;">​</a></h3><p><img src="`+h+`" alt="GeekBench-6-results"> [Screenshot: GeekBench 6 results comparing stock 2.4 GHz vs overclocked 3.1 GHz with DietPi OS]</p><h3 id="current-geekbench-6-records-as-of-december-18-2025" tabindex="-1">Current GeekBench 6 Records (as of December 18, 2025) <a class="header-anchor" href="#current-geekbench-6-records-as-of-december-18-2025" aria-label="Permalink to &quot;Current GeekBench 6 Records (as of December 18, 2025)&quot;">​</a></h3><p>The highest Raspberry Pi 5 scores we&#39;ve been able to locate:</p><table tabindex="0"><thead><tr><th>Record</th><th>SC Score</th><th>MC Score</th><th>Frequency</th><th>Model</th><th>Link</th></tr></thead><tbody><tr><td><strong>Best Single-Core</strong></td><td><strong>1195</strong></td><td>2481</td><td>3.40 GHz</td><td>Pi 5 Rev 1.1 (16GB)</td><td><a href="https://browser.geekbench.com/v6/cpu/9905864" target="_blank" rel="noreferrer">#9905864</a></td></tr><tr><td><strong>Best Multi-Core</strong></td><td>1180</td><td><strong>2529</strong></td><td>3.30 GHz</td><td>Pi 5 Rev 1.0 (8GB)</td><td><a href="https://browser.geekbench.com/v6/cpu/9922491" target="_blank" rel="noreferrer">#9922491</a></td></tr></tbody></table><p><strong>Note:</strong> These are extreme overclocking results requiring specialized cooling and are not representative of typical safe overclocking.</p><h3 id="other-benchmarks" tabindex="-1">Other Benchmarks <a class="header-anchor" href="#other-benchmarks" aria-label="Permalink to &quot;Other Benchmarks&quot;">​</a></h3><p><strong>sysbench (CPU):</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysbench</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sysbench</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cpu</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --threads=4</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div><p><strong>stress-ng:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stress-ng</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">stress-ng</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cpu</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --timeout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 60s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --metrics-brief</span></span></code></pre></div><p><strong>7-Zip compression benchmark:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> p7zip-full</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">7z</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> b</span></span></code></pre></div><hr><h2 id="os-performance-differences" tabindex="-1">OS Performance Differences <a class="header-anchor" href="#os-performance-differences" aria-label="Permalink to &quot;OS Performance Differences&quot;">​</a></h2><p>Your choice of operating system significantly impacts benchmark results.</p><h3 id="performance-comparison" tabindex="-1">Performance Comparison <a class="header-anchor" href="#performance-comparison" aria-label="Permalink to &quot;Performance Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Operating System</th><th>Performance</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Raspberry Pi OS Lite</strong></td><td>Excellent</td><td>Minimal overhead, optimized for Pi</td></tr><tr><td><strong>DietPi</strong></td><td>Excellent</td><td>Highly optimized, minimal footprint</td></tr><tr><td><strong>Raspberry Pi OS Desktop</strong></td><td>Very Good</td><td>More overhead from desktop environment</td></tr><tr><td><strong>Ubuntu Server</strong></td><td>Moderate</td><td>More generic, less Pi-optimized</td></tr><tr><td><strong>Ubuntu Desktop</strong></td><td>Lower</td><td>Significant desktop overhead</td></tr></tbody></table><h3 id="recommendation" tabindex="-1">Recommendation <a class="header-anchor" href="#recommendation" aria-label="Permalink to &quot;Recommendation&quot;">​</a></h3><p>For maximum overclocking performance and best benchmark scores, use:</p><ol><li><strong>Raspberry Pi OS Lite</strong> — Official, optimized, minimal</li><li><strong>DietPi</strong> — Community favorite, extremely lean</li></ol><p>Both provide noticeably better results than Ubuntu or other general-purpose distributions.</p><hr><h2 id="achievable-results-and-silicon-lottery" tabindex="-1">Achievable Results and Silicon Lottery <a class="header-anchor" href="#achievable-results-and-silicon-lottery" aria-label="Permalink to &quot;Achievable Results and Silicon Lottery&quot;">​</a></h2><p>Every BCM2712 chip is unique. Due to manufacturing variations, some chips can achieve higher stable frequencies than others.</p><h3 id="typical-results" tabindex="-1">Typical Results <a class="header-anchor" href="#typical-results" aria-label="Permalink to &quot;Typical Results&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Category</th><th>Frequency Range</th><th>Percentage of Chips</th></tr></thead><tbody><tr><td><strong>Average</strong></td><td>2.6-2.8 GHz</td><td>Most chips</td></tr><tr><td><strong>Good</strong></td><td>2.9-3.0 GHz</td><td>Many chips</td></tr><tr><td><strong>Excellent</strong></td><td>3.0-3.1 GHz</td><td>Some chips</td></tr><tr><td><strong>Exceptional</strong></td><td>3.1-3.2+ GHz</td><td>Rare</td></tr></tbody></table><h3 id="important-notes" tabindex="-1">Important Notes <a class="header-anchor" href="#important-notes" aria-label="Permalink to &quot;Important Notes&quot;">​</a></h3><ol><li><strong>Firmware limits:</strong> Older firmware capped at 3.0 GHz. Newer firmware allows higher, but &gt;3.0 GHz remains &quot;extreme&quot; territory.</li><li><strong>Silicon lottery:</strong> Your chip&#39;s maximum is predetermined — no amount of cooling or voltage will change it significantly.</li><li><strong>8GB model consideration:</strong> Reportedly, some 8GB models with Micron RAM may show reduced performance when overclocked due to SDRAM behavior differences. <strong>Update your firmware/EEPROM first</strong> — many SDRAM timing issues have been addressed in recent updates.</li></ol><p><em>Sources: <a href="https://github.com/raspberrypi/firmware/issues/1854" target="_blank" rel="noreferrer">GitHub — raspberrypi/firmware Issue #1854</a>, <a href="https://www.jeffgeerling.com/blog/2024/raspberry-pi-boosts-pi-5-performance-sdram-tuning" target="_blank" rel="noreferrer">Jeff Geerling — Raspberry Pi boosts Pi 5 performance with SDRAM tuning</a></em></p><h3 id="setting-realistic-expectations" tabindex="-1">Setting Realistic Expectations <a class="header-anchor" href="#setting-realistic-expectations" aria-label="Permalink to &quot;Setting Realistic Expectations&quot;">​</a></h3><ul><li><strong>2.6 GHz:</strong> Almost all chips can achieve this</li><li><strong>2.8 GHz:</strong> Most chips with adequate cooling</li><li><strong>3.0 GHz:</strong> Many chips, but not guaranteed</li><li><strong>3.0+ GHz:</strong> Requires silicon lottery win and excellent cooling</li></ul><hr><h2 id="best-practices-summary" tabindex="-1">Best Practices Summary <a class="header-anchor" href="#best-practices-summary" aria-label="Permalink to &quot;Best Practices Summary&quot;">​</a></h2><ol><li><strong>Always use active cooling</strong> — Passive cooling is insufficient for overclocking</li><li><strong>Use the official 27W power supply</strong> — Under-voltage causes instability and throttling</li><li><strong>Increment frequency in small steps</strong> — 50 MHz per iteration</li><li><strong>Test stability at each step</strong> — Use Pi-Under-Pressure</li><li><strong>Quick tests first (3m)</strong> — Save time during initial tuning</li><li><strong>Extended tests for final validation (1h+)</strong> — Confirm long-term stability</li><li><strong>Monitor throttling</strong> — Any throttling = unstable overclock</li><li><strong>Keep temperatures below 80°C</strong> — Ideally below 75°C under load</li><li><strong>Green report = stable</strong> — Only a green PASSED report means success</li><li><strong>Document your settings</strong> — Keep track of what works</li></ol><hr><h2 id="advanced-beyond-3-0-ghz" tabindex="-1">Advanced: Beyond 3.0 GHz <a class="header-anchor" href="#advanced-beyond-3-0-ghz" aria-label="Permalink to &quot;Advanced: Beyond 3.0 GHz&quot;">​</a></h2><p>Older Raspberry Pi firmware had a hard limit at 3.0 GHz. Newer firmware versions have relaxed this limit, allowing higher frequencies without custom patches. However, achieving frequencies above 3.0 GHz remains an &quot;extreme&quot; scenario:</p><ul><li><strong>3.14 GHz</strong> — Achieved by Jeff Geerling</li><li><strong>3.5 GHz</strong> — Achieved by Martin Rowan with dual Peltier cooling</li></ul><p><strong>Important warnings:</strong></p><ul><li>Risk of <strong>permanent hardware damage</strong> is significantly higher</li><li>Requires <strong>extreme cooling solutions</strong> (tower coolers, Peltier, liquid cooling)</li><li><strong>Most chips cannot achieve these frequencies</strong> regardless of cooling</li><li>This is <strong>not recommended</strong> for daily use or 24/7 operation</li></ul><p>This guide focuses on safe, practical overclocking. For extreme overclocking information, see:</p><ul><li><a href="https://www.jeffgeerling.com/blog/2024/raspberry-pi-5-can-overclock-314-ghz" target="_blank" rel="noreferrer">Jeff Geerling — Raspberry Pi 5 can overclock to 3.14 GHz</a></li><li><a href="https://www.martinrowan.co.uk/2024/09/raspberry-pi-5-overclocking-to-beat-geekbench-record/" target="_blank" rel="noreferrer">Martin Rowan — Raspberry Pi 5 Overclocking to Beat Geekbench Record</a></li></ul><hr><h2 id="faq-and-troubleshooting" tabindex="-1">FAQ and Troubleshooting <a class="header-anchor" href="#faq-and-troubleshooting" aria-label="Permalink to &quot;FAQ and Troubleshooting&quot;">​</a></h2><h3 id="q-my-pi-won-t-boot-after-overclocking-what-do-i-do" tabindex="-1">Q: My Pi won&#39;t boot after overclocking. What do I do? <a class="header-anchor" href="#q-my-pi-won-t-boot-after-overclocking-what-do-i-do" aria-label="Permalink to &quot;Q: My Pi won&#39;t boot after overclocking. What do I do?&quot;">​</a></h3><p><strong>A:</strong> Remove the microSD card, insert it into another computer, and edit <code>/boot/firmware/config.txt</code>. Comment out your overclock settings by adding <code>#</code> at the beginning of each line. Reinsert and boot.</p><h3 id="q-how-do-i-know-if-my-overclock-is-stable" tabindex="-1">Q: How do I know if my overclock is stable? <a class="header-anchor" href="#q-how-do-i-know-if-my-overclock-is-stable" aria-label="Permalink to &quot;Q: How do I know if my overclock is stable?&quot;">​</a></h3><p><strong>A:</strong> Run <a href="https://github.com/cmd0s/Pi-Under-Pressure" target="_blank" rel="noreferrer">Pi-Under-Pressure</a> for at least 1 hour. If the final report shows <strong>GREEN</strong> with <strong>PASSED</strong> and zero errors in all categories, your overclock is stable. Any errors, crashes, or throttling events mean it&#39;s not stable.</p><h3 id="q-what-s-the-maximum-safe-temperature" tabindex="-1">Q: What&#39;s the maximum safe temperature? <a class="header-anchor" href="#q-what-s-the-maximum-safe-temperature" aria-label="Permalink to &quot;Q: What&#39;s the maximum safe temperature?&quot;">​</a></h3><p><strong>A:</strong> Keep temperatures <strong>below 80°C</strong> under load for long-term reliability. The Pi will start throttling at 80°C and aggressively throttle at 85°C.</p><h3 id="q-my-fan-is-too-loud-can-i-adjust-it" tabindex="-1">Q: My fan is too loud. Can I adjust it? <a class="header-anchor" href="#q-my-fan-is-too-loud-can-i-adjust-it" aria-label="Permalink to &quot;Q: My fan is too loud. Can I adjust it?&quot;">​</a></h3><p><strong>A:</strong> Yes, modify the fan curve in <code>/boot/firmware/config.txt</code> using <code>dtparam=fan_tempX=</code> and <code>dtparam=fan_tempX_speed=</code> parameters. See the <a href="#fan-speed-configuration">Fan Speed Configuration</a> section.</p><h3 id="q-how-do-i-know-what-type-of-ram-is-in-my-device" tabindex="-1">Q: How do I know what type of RAM is in my device? <a class="header-anchor" href="#q-how-do-i-know-what-type-of-ram-is-in-my-device" aria-label="Permalink to &quot;Q: How do I know what type of RAM is in my device?&quot;">​</a></h3><p><strong>A:</strong> There&#39;s an unofficial method to check your RAM manufacturer via console command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vcgencmd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> otp_dump</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> awk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -F:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;/^30:/{h=tolower($2); v=substr(h,length(h)-3,1); print (v==&quot;0&quot;?&quot;Samsung&quot;:v==&quot;1&quot;||v==&quot;b&quot;?&quot;Micron&quot;:v==&quot;2&quot;?&quot;Hynix&quot;:&quot;Unknown&quot;)}&#39;</span></span></code></pre></div><p><strong>Note:</strong> This is an unofficial method based on data collected from forums and GitHub. There&#39;s no guarantee of its accuracy.</p><h3 id="q-should-i-use-over-voltage-or-over-voltage-delta" tabindex="-1">Q: Should I use over_voltage or over_voltage_delta? <a class="header-anchor" href="#q-should-i-use-over-voltage-or-over-voltage-delta" aria-label="Permalink to &quot;Q: Should I use over_voltage or over_voltage_delta?&quot;">​</a></h3><p><strong>A:</strong> Use <code>over_voltage_delta</code>. It preserves DVFS functionality, allowing the system to reduce voltage when idle, saving power and reducing heat.</p><h3 id="q-how-long-should-i-run-stability-tests" tabindex="-1">Q: How long should I run stability tests? <a class="header-anchor" href="#q-how-long-should-i-run-stability-tests" aria-label="Permalink to &quot;Q: How long should I run stability tests?&quot;">​</a></h3><p><strong>A:</strong> Use 3-minute tests for quick validation while tuning. Once you&#39;ve found a stable-looking configuration, run a 1-hour test. For maximum confidence, run overnight (8+ hours).</p><h3 id="q-why-do-i-get-throttling-even-with-good-cooling" tabindex="-1">Q: Why do I get throttling even with good cooling? <a class="header-anchor" href="#q-why-do-i-get-throttling-even-with-good-cooling" aria-label="Permalink to &quot;Q: Why do I get throttling even with good cooling?&quot;">​</a></h3><p><strong>A:</strong> Check your power supply. Throttling can be caused by under-voltage (weak power supply) not just temperature. Use <code>vcgencmd pmic_read_adc</code> to verify voltage and ensure you&#39;re using the official 27W power supply.</p><h3 id="q-can-i-overclock-with-passive-cooling" tabindex="-1">Q: Can I overclock with passive cooling? <a class="header-anchor" href="#q-can-i-overclock-with-passive-cooling" aria-label="Permalink to &quot;Q: Can I overclock with passive cooling?&quot;">​</a></h3><p><strong>A:</strong> Not recommended. While you might achieve a small overclock, sustained operation under load will likely cause thermal throttling, negating the performance gains and potentially causing instability.</p><h3 id="q-why-are-my-geekbench-scores-lower-than-others-at-the-same-frequency" tabindex="-1">Q: Why are my GeekBench scores lower than others at the same frequency? <a class="header-anchor" href="#q-why-are-my-geekbench-scores-lower-than-others-at-the-same-frequency" aria-label="Permalink to &quot;Q: Why are my GeekBench scores lower than others at the same frequency?&quot;">​</a></h3><p><strong>A:</strong> Several factors affect scores: silicon quality (lottery), RAM type, cooling efficiency, background processes, and operating system.</p><hr><h2 id="reference-links" tabindex="-1">Reference Links <a class="header-anchor" href="#reference-links" aria-label="Permalink to &quot;Reference Links&quot;">​</a></h2><h3 id="official-documentation" tabindex="-1">Official Documentation <a class="header-anchor" href="#official-documentation" aria-label="Permalink to &quot;Official Documentation&quot;">​</a></h3><ul><li><a href="https://www.raspberrypi.com/documentation/computers/config_txt.html" target="_blank" rel="noreferrer">Raspberry Pi config.txt Documentation</a></li><li><a href="https://www.raspberrypi.com/news/benchmarking-raspberry-pi-5/" target="_blank" rel="noreferrer">Benchmarking Raspberry Pi 5</a></li><li><a href="https://www.raspberrypi.com/news/heating-and-cooling-raspberry-pi-5/" target="_blank" rel="noreferrer">Heating and Cooling Raspberry Pi 5</a></li><li><a href="https://magazine.raspberrypi.com/issues/136" target="_blank" rel="noreferrer">The MagPi Magazine Issue 136</a></li></ul><h3 id="jeff-geerling-s-articles" tabindex="-1">Jeff Geerling&#39;s Articles <a class="header-anchor" href="#jeff-geerling-s-articles" aria-label="Permalink to &quot;Jeff Geerling&#39;s Articles&quot;">​</a></h3><ul><li><a href="https://www.jeffgeerling.com/blog/2023/overclocking-and-underclocking-raspberry-pi-5" target="_blank" rel="noreferrer">Overclocking and Underclocking Raspberry Pi 5</a></li><li><a href="https://www.jeffgeerling.com/blog/2024/important-consideration-about-pi-5-overclocking" target="_blank" rel="noreferrer">Important Consideration About Pi 5 Overclocking</a></li><li><a href="https://www.jeffgeerling.com/blog/2024/raspberry-pi-5-can-overclock-314-ghz" target="_blank" rel="noreferrer">Raspberry Pi 5 Can Overclock to 3.14 GHz</a></li><li><a href="https://www.jeffgeerling.com/blog/2024/raspberry-pi-boosts-pi-5-performance-sdram-tuning" target="_blank" rel="noreferrer">Raspberry Pi Boosts Pi 5 Performance with SDRAM Tuning</a></li></ul><h3 id="tom-s-hardware" tabindex="-1">Tom&#39;s Hardware <a class="header-anchor" href="#tom-s-hardware" aria-label="Permalink to &quot;Tom&#39;s Hardware&quot;">​</a></h3><ul><li><a href="https://www.tomshardware.com/news/overclocking-raspberry-pi-5" target="_blank" rel="noreferrer">Overclocking Raspberry Pi 5</a></li><li><a href="https://www.tomshardware.com/raspberry-pi/how-to-overclock-the-raspberry-pi-5-beyond-3-ghz" target="_blank" rel="noreferrer">How to Overclock the Raspberry Pi 5 Beyond 3 GHz</a></li></ul><h3 id="community-resources" tabindex="-1">Community Resources <a class="header-anchor" href="#community-resources" aria-label="Permalink to &quot;Community Resources&quot;">​</a></h3><ul><li><a href="https://core-electronics.com.au/guides/answering-your-pi-5-questions-cooling-overclocking-power-and-more/" target="_blank" rel="noreferrer">Core Electronics — Pi 5 Questions: Cooling, Overclocking, Power</a></li><li><a href="https://dietpi.com/forum/t/guide-to-pi-5-under-overclocking/19283" target="_blank" rel="noreferrer">DietPi Forum — Guide to Pi 5 Under/Overclocking</a></li><li><a href="https://www.linuxlinks.com/raspberry-pi5-desktop-mini-pc-overclocking/" target="_blank" rel="noreferrer">LinuxLinks — Raspberry Pi 5 Overclocking</a></li></ul><h3 id="raspberry-pi-forums" tabindex="-1">Raspberry Pi Forums <a class="header-anchor" href="#raspberry-pi-forums" aria-label="Permalink to &quot;Raspberry Pi Forums&quot;">​</a></h3><ul><li><a href="https://forums.raspberrypi.com/viewtopic.php?t=362296" target="_blank" rel="noreferrer">Overclocking Discussion Thread</a></li><li><a href="https://forums.raspberrypi.com/viewtopic.php?t=359523" target="_blank" rel="noreferrer">Pi 5 8GB Overclock Not Working</a></li><li><a href="https://forums.raspberrypi.com/viewtopic.php?t=386147" target="_blank" rel="noreferrer">Integrated Fan Controller</a></li></ul><h3 id="github-resources" tabindex="-1">GitHub Resources <a class="header-anchor" href="#github-resources" aria-label="Permalink to &quot;GitHub Resources&quot;">​</a></h3><ul><li><a href="https://github.com/cmd0s/Pi-Under-Pressure" target="_blank" rel="noreferrer">Pi-Under-Pressure — Stability Testing Tool</a></li><li><a href="https://github.com/raspberrypi/rpi-eeprom" target="_blank" rel="noreferrer">raspberrypi/rpi-eeprom — Firmware Repository</a></li><li><a href="https://github.com/raspberrypi/firmware/issues/1854" target="_blank" rel="noreferrer">Firmware Issue #1854 — SDRAM Performance</a></li></ul><h3 id="extreme-overclocking" tabindex="-1">Extreme Overclocking <a class="header-anchor" href="#extreme-overclocking" aria-label="Permalink to &quot;Extreme Overclocking&quot;">​</a></h3><ul><li><a href="https://www.martinrowan.co.uk/2024/09/raspberry-pi-5-overclocking-to-beat-geekbench-record/" target="_blank" rel="noreferrer">Martin Rowan — Pi 5 Overclocking to Beat Geekbench Record</a></li></ul><h3 id="youtube-resources" tabindex="-1">YouTube Resources <a class="header-anchor" href="#youtube-resources" aria-label="Permalink to &quot;YouTube Resources&quot;">​</a></h3><ul><li><a href="https://www.youtube.com/watch?v=RV1mfbwAB58" target="_blank" rel="noreferrer">Raspberry Pi 5 Overclocking Guide</a></li><li><a href="https://www.youtube.com/watch?v=TTIkZBsVJyA" target="_blank" rel="noreferrer">Pi 5 Cooling Solutions Compared</a></li><li><a href="https://www.youtube.com/watch?v=K6dWE2x4viw" target="_blank" rel="noreferrer">Overclocking Pi 5 to 3 GHz</a></li><li><a href="https://www.youtube.com/watch?v=bTnBCSV6Kow" target="_blank" rel="noreferrer">Pi 5 Performance Testing</a></li><li><a href="https://www.youtube.com/watch?v=3zlteWp6ro0" target="_blank" rel="noreferrer">Raspberry Pi 5 Benchmarks</a></li><li><a href="https://www.youtube.com/watch?v=_tnm18_L5I8" target="_blank" rel="noreferrer">Pi 5 Active Cooling Test</a></li><li><a href="https://www.youtube.com/watch?v=hBAYiJTRG4M" target="_blank" rel="noreferrer">Overclocking Stability Guide</a></li><li><a href="https://www.youtube.com/watch?v=ruXQ4eYh4dA" target="_blank" rel="noreferrer">Pi 5 Extreme Overclocking</a></li></ul><hr><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>Overclocking your Raspberry Pi 5 can unlock significant additional performance when done correctly. The key is a methodical approach:</p><ol><li><strong>Increment slowly</strong> — 50 MHz steps</li><li><strong>Test thoroughly</strong> — Use Pi-Under-Pressure at each step</li><li><strong>Monitor everything</strong> — Temperature, throttling, errors</li><li><strong>Validate completely</strong> — Extended tests before daily use</li></ol><p>Remember that every chip is different. Your maximum stable frequency depends on silicon lottery, but with patience and proper testing, you can find the optimal balance between performance and stability for your specific unit.</p><p><strong>Happy overclocking!</strong></p><hr><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Overclock in 50 MHz steps; validate each step with <strong>Pi-Under-Pressure</strong> (3-minute quick checks, then 1+ hour final validation).</li><li>Prefer <code>over_voltage_delta</code> over legacy <code>over_voltage</code> to keep DVFS and lower idle heat.</li><li>Active cooling and the official 27W PSU are mandatory; any throttling during stress tests means the OC is not stable.</li><li>Typical stable targets are <strong>2.6–3.0 GHz</strong> depending on silicon lottery; D0 stepping runs cooler but does not guarantee higher max frequency.</li><li>PCIe Gen 3 (<code>dtparam=pciex1_gen=3</code>) roughly doubles NVMe bandwidth and is generally reliable for daily use.</li></ul>`,349)])])}const v=t(p,[["render",c]]);export{f as __pageData,v as default};
